cardCss:
/*
 * HOLLOW KNIGHT LORE TABLET
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Pale carved stone tablet — Hollow Knight's quiet, ruined
 *             civilisation; incised glyphs, atmospheric low-angle light
 * Fonts     : Cinzel Decorative (term, decorative glyphs) · Cinzel (body)
 * Palette   : limestone #cfc8b8 · shadow #7a6e60 · amber #c8a060
 * Background: SVG feTurbulence (fractalNoise 0.035, 6 octaves) →
 *             feDiffuseLighting (diffuseConstant 1.2, surfaceScale 4) →
 *             feDistantLight at azimuth 210° elevation 12° — low raking
 *             angle exaggerates micro-relief of carved stone surface
 *             feComposite multiply blends over stone base colour
 * Vignette  : radial-gradient overlay darkens corners (ruined, atmospheric)
 * Border    : CSS box border with pseudo-element corner notches suggesting
 *             a stone slab's chipped edges
 */

@import url("https://fonts.googleapis.com/css2?family=Cinzel+Decorative:wght@400;700&family=Cinzel:wght@400;600&display=swap");

:root {
  --hk-stone:  #e8e0d0;
  --hk-shadow: #7a6e60;
  --hk-amber:  #c8a060;
  --hk-ink:    #1a1208;
  --hk-light:  #e8e0d0;
}

html, body, div#qa { height: 100%; }

.card { background: var(--hk-stone); min-height: 100%; }

.off-screen { position: absolute; left: -9999px; }

.hk-card {
  min-height: 100%;
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  overflow: hidden;
  box-sizing: border-box;
  border: 2px solid var(--hk-shadow);
  outline: 6px solid var(--hk-stone);
  outline-offset: -10px;
}

.hk-stone-layer {
  position: absolute;
  inset: 0;
  background: var(--hk-stone);
  filter: url(#hk-stone) brightness(1.35);
  pointer-events: none;
  z-index: 0;
}

.hk-stone-layer--back { filter: url(#hk-stone) brightness(1.12); }

.hk-vignette {
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse at center, transparent 35%, rgba(50,38,28,0.55) 100%);
  pointer-events: none;
  z-index: 1;
}

.hk-content {
  position: relative;
  z-index: 2;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 2.5rem 2rem;
  width: 100%;
  box-sizing: border-box;
}

.hk-glyph-deco {
  font-family: "Cinzel Decorative", serif;
  font-size: 1.1rem;
  color: var(--hk-shadow);
  opacity: 0.5;
  letter-spacing: 1rem;
  margin: 0 0 1.2rem;
}

.hk-prompt {
  font-family: "Cinzel", serif;
  font-size: 1.6rem;
  color: var(--hk-ink);
  opacity: 0.95;
  letter-spacing: 0.12em;
  margin: 0 0 1.4rem;
}

.hk-term {
  font-family: "Cinzel Decorative", serif;
  font-size: 5rem;
  font-weight: 700;
  color: var(--hk-ink);
  text-shadow: 0 2px 4px rgba(50,38,28,0.2);
  margin: 0 0 0.6rem;
  line-height: 1.2;
  letter-spacing: 0.05em;
}

.hk-reading { font-family: "Cinzel", serif; font-size: 2.4rem; color: var(--hk-amber); margin: 0 0 0.4rem; }
.hk-translation { font-family: "Cinzel", serif; font-size: 1.8rem; color: var(--hk-ink); opacity: 0.8; margin: 0 0 0.3rem; }
.hk-transliteration { font-family: "Cinzel", serif; font-size: 1.5rem; color: var(--hk-shadow); font-style: italic; margin: 0; }
.hk-tags { font-family: "Cinzel", serif; font-size: 0.85rem; color: var(--hk-shadow); opacity: 0.5; margin: 0.5rem 0 0; }

.hk-rule { border: none; border-top: 1px solid var(--hk-shadow); width: 60%; margin: 0.8rem auto; opacity: 0.4; }

.hk-input-wrap { width: 100%; max-width: 26rem; }
.hk-input-wrap input {
  font-family: "Cinzel", serif;
  font-size: 1.1rem;
  background: rgba(255,252,245,0.75);
  border: none;
  border-bottom: 2px solid var(--hk-shadow);
  color: var(--hk-ink);
  width: 100%;
  padding: 0.4rem 0;
  text-align: center;
  letter-spacing: 0.1em;
}
.hk-input-wrap input:focus { outline: none; border-bottom-color: var(--hk-amber); background: rgba(255,252,245,0.95); }
.hk-input-wrap input::placeholder { color: var(--hk-shadow); opacity: 0.7; }

.hk-hint-wrap { margin-top: 1rem; }
.hk-hint-link { font-family: "Cinzel", serif; font-size: 0.85rem; color: var(--hk-shadow); opacity: 0.55; text-decoration: underline; }
.hk-hint-text { font-family: "Cinzel", serif; font-size: 1rem; color: var(--hk-ink); opacity: 0.65; margin-top: 0.4rem; }
.hk-audio { margin: 0 0 1rem; }

.hk-picture img {
  max-width: 100%;
  max-height: 22rem;
  object-fit: contain;
  filter: sepia(0.3) contrast(0.9) brightness(0.85);
  margin-top: 1rem;
}

.append-play-btn-text a::after { content: "▶"; color: var(--hk-ink); }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 2rem; cursor: pointer; color: var(--hk-ink); }
